import{ad as a,o as n,c as p,au as l}from"./chunks/framework.C_jK3ma9.js";const h=JSON.parse('{"title":"Resource","description":"","frontmatter":{},"headers":[],"relativePath":"docs/data-fetching/resource.md","filePath":"docs/data-fetching/resource.md","lastUpdated":1767261019000}'),c={name:"docs/data-fetching/resource.md"};function e(t,s,o,_,i,r){return n(),p("div",null,[...s[0]||(s[0]=[l(`<h1 id="resource" tabindex="-1">Resource <a class="header-anchor" href="#resource" aria-label="Permalink to “Resource”">​</a></h1><p>Resource is a feature to manage async data fetching and mutations in your Vue frontend. It will fetch, cache and keep data up-to-date from the server.</p><h2 id="basic-example" tabindex="-1">Basic example <a class="header-anchor" href="#basic-example" aria-label="Permalink to “Basic example”">​</a></h2><p>Any data that is fetched via a web request is called a resource in frappe-ui terminology. When you are dealing with async data, you are also dealing with loading states, error states, refetching etc. In the traditional way of fetching data, you have to handle loading states, error states, and refetching yourself.</p><div class="language-js"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki shiki-themes tokyo-night github-light s_2cy0ei" tabindex="0" dir="ltr"><code><span class="line"><span class="s_252irl">let</span><span class="s_2a1oer"> data</span><span class="s_1jjt6x">,</span><span class="s_2a1oer"> loading</span><span class="s_1jjt6x">,</span><span class="s_2a1oer"> error</span></span>
<span class="line"><span class="s_50ecpt">try</span><span class="s_13ahmt"> {</span></span>
<span class="line"><span class="s_22m8k2">  data</span><span class="s_2ekfrt"> =</span><span class="s_29n2kq"> await</span><span class="s_indoxt"> fetch</span><span class="s_13ahmt">(</span><span class="s_w1p9wo">&#39;</span><span class="s_2575z4">https://jsonplaceholder.typicode.com/posts/1</span><span class="s_w1p9wo">&#39;</span><span class="s_13ahmt">)</span></span>
<span class="line"><span class="s_13ahmt">}</span><span class="s_50ecpt"> catch</span><span class="s_13ahmt"> (</span><span class="s_22m8k2">e</span><span class="s_13ahmt">)</span><span class="s_13ahmt"> {</span></span>
<span class="line"><span class="s_22m8k2">  error</span><span class="s_2ekfrt"> =</span><span class="s_22m8k2"> e</span></span>
<span class="line"><span class="s_13ahmt">}</span></span>
<span class="line"><span class="s_1th9sy">// rest of your code</span></span></code></pre></div><p>The above example is still a very simplified version. You might also need a way to reload your data.</p><p>When you create a resource using the <code>createResource</code> function, it will create a reactive object with properties like <code>data</code>, <code>loading</code>, <code>error</code>, <code>reload()</code> etc.</p><p>The default request method is <code>POST</code>. This can be changed in the <code>options</code> object.</p><div class="language-vue"><button title="Copy Code" class="copy"></button><span class="lang">vue</span><pre class="shiki shiki-themes tokyo-night github-light s_2cy0ei" tabindex="0" dir="ltr"><code><span class="line"><span class="s_1zd9e2">&lt;</span><span class="s_1uuh8p">template</span><span class="s_1zd9e2">&gt;</span></span>
<span class="line"><span class="s_1zd9e2">  &lt;</span><span class="s_1uuh8p">Button</span><span class="s_1i4ay4"> @click</span><span class="s_1jjt6x">=</span><span class="s_w1p9wo">&quot;</span><span class="s_2575z4">post.reload()</span><span class="s_w1p9wo">&quot;</span><span class="s_1i4ay4"> :loading</span><span class="s_1jjt6x">=</span><span class="s_w1p9wo">&quot;</span><span class="s_2575z4">post.loading</span><span class="s_w1p9wo">&quot;</span><span class="s_1zd9e2">&gt;</span><span class="s_6am9cx"> Reload </span><span class="s_1zd9e2">&lt;/</span><span class="s_1uuh8p">Button</span><span class="s_1zd9e2">&gt;</span></span>
<span class="line"><span class="s_1zd9e2">  &lt;</span><span class="s_1uuh8p">pre</span><span class="s_1zd9e2">&gt;</span><span class="s_6am9cx">{{ post }}</span><span class="s_1zd9e2">&lt;/</span><span class="s_1uuh8p">pre</span><span class="s_1zd9e2">&gt;</span></span>
<span class="line"><span class="s_1zd9e2">&lt;/</span><span class="s_1uuh8p">template</span><span class="s_1zd9e2">&gt;</span></span>
<span class="line"></span>
<span class="line"><span class="s_1zd9e2">&lt;</span><span class="s_1uuh8p">script</span><span class="s_1i4ay4"> setup</span><span class="s_1zd9e2">&gt;</span></span>
<span class="line"><span class="s_edvzsf">import</span><span class="s_13ahmt"> { </span><span class="s_4q1z3w">createResource</span><span class="s_13ahmt"> }</span><span class="s_edvzsf"> from</span><span class="s_w1p9wo"> &#39;</span><span class="s_2575z4">frappe-ui</span><span class="s_w1p9wo">&#39;</span></span>
<span class="line"><span class="s_252irl">let</span><span class="s_2a1oer"> post</span><span class="s_2ekfrt"> =</span><span class="s_indoxt"> createResource</span><span class="s_13ahmt">({</span></span>
<span class="line"><span class="s_r4oegk">  url</span><span class="s_1jjt6x">:</span><span class="s_w1p9wo"> &#39;</span><span class="s_2575z4">https://jsonplaceholder.typicode.com/posts/1</span><span class="s_w1p9wo">&#39;</span><span class="s_1jjt6x">,</span></span>
<span class="line"><span class="s_r4oegk">  method</span><span class="s_1jjt6x">:</span><span class="s_w1p9wo"> &#39;</span><span class="s_2575z4">GET</span><span class="s_w1p9wo">&#39;</span><span class="s_1jjt6x">,</span></span>
<span class="line"><span class="s_13ahmt">})</span></span>
<span class="line"><span class="s_22m8k2">post</span><span class="s_1jjt6x">.</span><span class="s_indoxt">fetch</span><span class="s_13ahmt">()</span></span>
<span class="line"><span class="s_1zd9e2">&lt;/</span><span class="s_1uuh8p">script</span><span class="s_1zd9e2">&gt;</span></span></code></pre></div><h2 id="options-api-example" tabindex="-1">Options API example <a class="header-anchor" href="#options-api-example" aria-label="Permalink to “Options API example”">​</a></h2><p>Resources can also be used in options API style. You need to register the <code>resourcesPlugin</code> first.</p><p><strong>main.js</strong></p><div class="language-js"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki shiki-themes tokyo-night github-light s_2cy0ei" tabindex="0" dir="ltr"><code><span class="line"><span class="s_edvzsf">import</span><span class="s_13ahmt"> { </span><span class="s_4q1z3w">resourcesPlugin</span><span class="s_13ahmt"> }</span><span class="s_edvzsf"> from</span><span class="s_w1p9wo"> &#39;</span><span class="s_2575z4">frappe-ui</span><span class="s_w1p9wo">&#39;</span></span>
<span class="line"><span class="s_22m8k2">app</span><span class="s_1jjt6x">.</span><span class="s_indoxt">use</span><span class="s_13ahmt">(</span><span class="s_22m8k2">resourcesPlugin</span><span class="s_13ahmt">)</span></span></code></pre></div><p>In your <code>.vue</code> file, you can declare all your resources under the <code>resources</code> key as functions. The actual resource object will be available on <code>this.$resources.[name]</code>. In the following example, <code>this.$resources.posts</code> is the resource object.</p><p><strong>Component.vue</strong></p><div class="language-vue"><button title="Copy Code" class="copy"></button><span class="lang">vue</span><pre class="shiki shiki-themes tokyo-night github-light s_2cy0ei" tabindex="0" dir="ltr"><code><span class="line"><span class="s_1zd9e2">&lt;</span><span class="s_1uuh8p">template</span><span class="s_1zd9e2">&gt;</span></span>
<span class="line"><span class="s_1zd9e2">  &lt;</span><span class="s_1uuh8p">pre</span><span class="s_1zd9e2">&gt;</span><span class="s_6am9cx">{{ $resources.posts }}</span><span class="s_1zd9e2">&lt;/</span><span class="s_1uuh8p">pre</span><span class="s_1zd9e2">&gt;</span></span>
<span class="line"><span class="s_1zd9e2">&lt;/</span><span class="s_1uuh8p">template</span><span class="s_1zd9e2">&gt;</span></span>
<span class="line"><span class="s_1zd9e2">&lt;</span><span class="s_1uuh8p">script</span><span class="s_1zd9e2">&gt;</span></span>
<span class="line"><span class="s_edvzsf">export</span><span class="s_edvzsf"> default</span><span class="s_13ahmt"> {</span></span>
<span class="line"><span class="s_r4oegk">  resources</span><span class="s_1jjt6x">:</span><span class="s_13ahmt"> {</span></span>
<span class="line"><span class="s_indoxt">    posts</span><span class="s_13ahmt">()</span><span class="s_13ahmt"> {</span></span>
<span class="line"><span class="s_29n2kq">      return</span><span class="s_13ahmt"> {</span></span>
<span class="line"><span class="s_r4oegk">        url</span><span class="s_1jjt6x">:</span><span class="s_w1p9wo"> &#39;</span><span class="s_2575z4">https://jsonplaceholder.typicode.com/posts/1</span><span class="s_w1p9wo">&#39;</span><span class="s_1jjt6x">,</span></span>
<span class="line"><span class="s_1th9sy">        // option to call .fetch() the first time automatically</span></span>
<span class="line"><span class="s_r4oegk">        auto</span><span class="s_1jjt6x">:</span><span class="s_40mev6"> true</span><span class="s_1jjt6x">,</span></span>
<span class="line"><span class="s_13ahmt">      }</span></span>
<span class="line"><span class="s_13ahmt">    }</span><span class="s_1jjt6x">,</span></span>
<span class="line"><span class="s_13ahmt">  }</span><span class="s_1jjt6x">,</span></span>
<span class="line"><span class="s_13ahmt">}</span></span>
<span class="line"><span class="s_1zd9e2">&lt;/</span><span class="s_1uuh8p">script</span><span class="s_1zd9e2">&gt;</span></span></code></pre></div><h2 id="caching-example" tabindex="-1">Caching example <a class="header-anchor" href="#caching-example" aria-label="Permalink to “Caching example”">​</a></h2><p>Caching is a first-class feature in resources. To cache responses, just define a <code>cache</code> property in options with a unique global key. Now, the response will cached in memory as well as in IndexedDB. If you define another resource in a different part of your application with the same cache key, it will reuse the cached one.</p><div class="language-vue"><button title="Copy Code" class="copy"></button><span class="lang">vue</span><pre class="shiki shiki-themes tokyo-night github-light s_2cy0ei" tabindex="0" dir="ltr"><code><span class="line"><span class="s_1zd9e2">&lt;</span><span class="s_1uuh8p">template</span><span class="s_1zd9e2">&gt;</span></span>
<span class="line"><span class="s_1zd9e2">  &lt;</span><span class="s_1uuh8p">Button</span><span class="s_1i4ay4"> @click</span><span class="s_1jjt6x">=</span><span class="s_w1p9wo">&quot;</span><span class="s_2575z4">post.reload()</span><span class="s_w1p9wo">&quot;</span><span class="s_1i4ay4"> :loading</span><span class="s_1jjt6x">=</span><span class="s_w1p9wo">&quot;</span><span class="s_2575z4">post.loading</span><span class="s_w1p9wo">&quot;</span><span class="s_1zd9e2">&gt;</span></span>
<span class="line"><span class="s_6am9cx">    {{ post.fetched ? &#39;Reload&#39; : &#39;Fetch data&#39; }}</span></span>
<span class="line"><span class="s_1zd9e2">  &lt;/</span><span class="s_1uuh8p">Button</span><span class="s_1zd9e2">&gt;</span></span>
<span class="line"><span class="s_1zd9e2">  &lt;</span><span class="s_1uuh8p">pre</span><span class="s_1zd9e2">&gt;</span><span class="s_6am9cx">{{ post.data }}</span><span class="s_1zd9e2">&lt;/</span><span class="s_1uuh8p">pre</span><span class="s_1zd9e2">&gt;</span></span>
<span class="line"><span class="s_1zd9e2">&lt;/</span><span class="s_1uuh8p">template</span><span class="s_1zd9e2">&gt;</span></span>
<span class="line"></span>
<span class="line"><span class="s_1zd9e2">&lt;</span><span class="s_1uuh8p">script</span><span class="s_1i4ay4"> setup</span><span class="s_1zd9e2">&gt;</span></span>
<span class="line"><span class="s_edvzsf">import</span><span class="s_13ahmt"> { </span><span class="s_4q1z3w">createResource</span><span class="s_13ahmt"> }</span><span class="s_edvzsf"> from</span><span class="s_w1p9wo"> &#39;</span><span class="s_2575z4">frappe-ui</span><span class="s_w1p9wo">&#39;</span></span>
<span class="line"><span class="s_252irl">let</span><span class="s_2a1oer"> post</span><span class="s_2ekfrt"> =</span><span class="s_indoxt"> createResource</span><span class="s_13ahmt">({</span></span>
<span class="line"><span class="s_r4oegk">  url</span><span class="s_1jjt6x">:</span><span class="s_w1p9wo"> &#39;</span><span class="s_2575z4">https://jsonplaceholder.typicode.com/posts/1</span><span class="s_w1p9wo">&#39;</span><span class="s_1jjt6x">,</span></span>
<span class="line"><span class="s_r4oegk">  cache</span><span class="s_1jjt6x">:</span><span class="s_w1p9wo"> &#39;</span><span class="s_2575z4">posts</span><span class="s_w1p9wo">&#39;</span><span class="s_1jjt6x">,</span></span>
<span class="line"><span class="s_13ahmt">})</span></span>
<span class="line"><span class="s_1zd9e2">&lt;/</span><span class="s_1uuh8p">script</span><span class="s_1zd9e2">&gt;</span></span></code></pre></div><h2 id="list-of-options-and-api" tabindex="-1">List of Options and API <a class="header-anchor" href="#list-of-options-and-api" aria-label="Permalink to “List of Options and API”">​</a></h2><p>Here is the list of all options and APIs that are available on a resource.</p><h3 id="options" tabindex="-1">Options <a class="header-anchor" href="#options" aria-label="Permalink to “Options”">​</a></h3><div class="language-js"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki shiki-themes tokyo-night github-light s_2cy0ei" tabindex="0" dir="ltr"><code><span class="line"><span class="s_252irl">let</span><span class="s_2a1oer"> post</span><span class="s_2ekfrt"> =</span><span class="s_indoxt"> createResource</span><span class="s_13ahmt">({</span></span>
<span class="line"><span class="s_1th9sy">    // partial rest api routes</span></span>
<span class="line"><span class="s_r4oegk">    url</span><span class="s_1jjt6x">:</span><span class="s_w1p9wo"> &#39;</span><span class="s_2575z4">/api/posts/1</span><span class="s_w1p9wo">&#39;</span></span>
<span class="line"><span class="s_1th9sy">    // or full urls</span></span>
<span class="line"><span class="s_22m8k2">    url</span><span class="s_kq5psm">: </span><span class="s_w1p9wo">&#39;</span><span class="s_2575z4">https://jsonplaceholder.typicode.com/posts/1</span><span class="s_w1p9wo">&#39;</span><span class="s_1jjt6x">,</span></span>
<span class="line"></span>
<span class="line"><span class="s_1th9sy">    // http method: GET, POST, PUT, DELETE</span></span>
<span class="line"><span class="s_r4oegk">    method</span><span class="s_1jjt6x">:</span><span class="s_w1p9wo"> &#39;</span><span class="s_2575z4">GET</span><span class="s_w1p9wo">&#39;</span><span class="s_1jjt6x">,</span></span>
<span class="line"></span>
<span class="line"><span class="s_1th9sy">    // parameters</span></span>
<span class="line"><span class="s_r4oegk">    params</span><span class="s_1jjt6x">:</span><span class="s_13ahmt"> {</span></span>
<span class="line"><span class="s_r4oegk">      id</span><span class="s_1jjt6x">:</span><span class="s_40mev6"> 1</span></span>
<span class="line"><span class="s_13ahmt">    }</span><span class="s_1jjt6x">,</span></span>
<span class="line"><span class="s_1th9sy">    // generate params from function</span></span>
<span class="line"><span class="s_indoxt">    makeParams</span><span class="s_13ahmt">()</span><span class="s_13ahmt"> {</span></span>
<span class="line"><span class="s_29n2kq">      return</span><span class="s_13ahmt"> {</span></span>
<span class="line"><span class="s_r4oegk">        id</span><span class="s_1jjt6x">:</span><span class="s_40mev6"> 1</span></span>
<span class="line"><span class="s_13ahmt">      }</span></span>
<span class="line"><span class="s_13ahmt">    }</span><span class="s_1jjt6x">,</span></span>
<span class="line"></span>
<span class="line"><span class="s_1th9sy">    // debounce request every 500ms</span></span>
<span class="line"><span class="s_r4oegk">    debounce</span><span class="s_1jjt6x">:</span><span class="s_40mev6"> 500</span><span class="s_1jjt6x">,</span></span>
<span class="line"></span>
<span class="line"><span class="s_1th9sy">    // initial data</span></span>
<span class="line"><span class="s_r4oegk">    initialData</span><span class="s_1jjt6x">:</span><span class="s_13ahmt"> []</span></span>
<span class="line"></span>
<span class="line"><span class="s_1th9sy">    // make the first request automatically</span></span>
<span class="line"><span class="s_22m8k2">    auto</span><span class="s_kq5psm">: </span><span class="s_40mev6">true</span><span class="s_1jjt6x">,</span></span>
<span class="line"></span>
<span class="line"><span class="s_1th9sy">    // cache key to cache the resource</span></span>
<span class="line"><span class="s_1th9sy">    // can be a string</span></span>
<span class="line"><span class="s_r4oegk">    cache</span><span class="s_1jjt6x">:</span><span class="s_w1p9wo"> &#39;</span><span class="s_2575z4">post</span><span class="s_w1p9wo">&#39;</span><span class="s_1jjt6x">,</span></span>
<span class="line"><span class="s_1th9sy">    // or an array that can be serialized</span></span>
<span class="line"><span class="s_r4oegk">    cache</span><span class="s_1jjt6x">:</span><span class="s_13ahmt"> [</span><span class="s_w1p9wo">&#39;</span><span class="s_2575z4">post</span><span class="s_w1p9wo">&#39;</span><span class="s_1jjt6x">,</span><span class="s_w1p9wo"> &#39;</span><span class="s_2575z4">1</span><span class="s_w1p9wo">&#39;</span><span class="s_13ahmt">]</span><span class="s_1jjt6x">,</span></span>
<span class="line"><span class="s_1th9sy">    // you can also pass reactive variable here</span></span>
<span class="line"><span class="s_r4oegk">    cache</span><span class="s_1jjt6x">:</span><span class="s_13ahmt"> [</span><span class="s_w1p9wo">&#39;</span><span class="s_2575z4">post</span><span class="s_w1p9wo">&#39;</span><span class="s_1jjt6x">,</span><span class="s_11933w"> postId</span><span class="s_13ahmt">]</span></span>
<span class="line"></span>
<span class="line"><span class="s_1th9sy">    // events</span></span>
<span class="line"><span class="s_1th9sy">    // before making the request</span></span>
<span class="line"><span class="s_indoxt">    beforeSubmit</span><span class="s_13ahmt">(</span><span class="s_22m8k2">params</span><span class="s_13ahmt">)</span><span class="s_13ahmt"> {</span></span>
<span class="line"></span>
<span class="line"><span class="s_13ahmt">    }</span><span class="s_1jjt6x">,</span></span>
<span class="line"><span class="s_1th9sy">    // validate parameters before making request</span></span>
<span class="line"><span class="s_indoxt">    validate</span><span class="s_13ahmt">(</span><span class="s_fsg3al">params</span><span class="s_13ahmt">)</span><span class="s_13ahmt"> {</span></span>
<span class="line"><span class="s_50ecpt">        if</span><span class="s_13ahmt"> (</span><span class="s_50ecpt">!</span><span class="s_22m8k2">params</span><span class="s_1jjt6x">.</span><span class="s_11933w">id</span><span class="s_13ahmt">) {</span></span>
<span class="line"><span class="s_1th9sy">            // return a string message to throw an error</span></span>
<span class="line"><span class="s_29n2kq">            return</span><span class="s_w1p9wo"> &#39;</span><span class="s_2575z4">id is required</span><span class="s_w1p9wo">&#39;</span></span>
<span class="line"><span class="s_13ahmt">        }</span></span>
<span class="line"><span class="s_13ahmt">    }</span><span class="s_1jjt6x">,</span></span>
<span class="line"><span class="s_1th9sy">    // error can occur from failed request and validate function</span></span>
<span class="line"><span class="s_indoxt">    onError</span><span class="s_13ahmt">(</span><span class="s_fsg3al">error</span><span class="s_13ahmt">)</span><span class="s_13ahmt"> {</span></span>
<span class="line"></span>
<span class="line"><span class="s_13ahmt">    }</span><span class="s_1jjt6x">,</span></span>
<span class="line"><span class="s_1th9sy">    // on successful response</span></span>
<span class="line"><span class="s_indoxt">    onSuccess</span><span class="s_13ahmt">(</span><span class="s_fsg3al">data</span><span class="s_13ahmt">)</span><span class="s_13ahmt"> {</span></span>
<span class="line"></span>
<span class="line"><span class="s_13ahmt">    }</span><span class="s_1jjt6x">,</span></span>
<span class="line"><span class="s_1th9sy">    // transform data before setting it</span></span>
<span class="line"><span class="s_indoxt">    transform</span><span class="s_13ahmt">(</span><span class="s_fsg3al">data</span><span class="s_13ahmt">)</span><span class="s_13ahmt"> {</span></span>
<span class="line"><span class="s_50ecpt">      for</span><span class="s_13ahmt"> (</span><span class="s_252irl">let</span><span class="s_2a1oer"> d</span><span class="s_2ekfrt"> of</span><span class="s_22m8k2"> data</span><span class="s_13ahmt">) {</span></span>
<span class="line"><span class="s_22m8k2">        d</span><span class="s_1jjt6x">.</span><span class="s_11933w">open</span><span class="s_2ekfrt"> =</span><span class="s_40mev6"> false</span></span>
<span class="line"><span class="s_13ahmt">      }</span></span>
<span class="line"><span class="s_29n2kq">      return</span><span class="s_22m8k2"> data</span></span>
<span class="line"><span class="s_13ahmt">    }</span><span class="s_1jjt6x">,</span></span>
<span class="line"><span class="s_13ahmt">})</span></span></code></pre></div><h3 id="api" tabindex="-1">API <a class="header-anchor" href="#api" aria-label="Permalink to “API”">​</a></h3><div class="language-js"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki shiki-themes tokyo-night github-light s_2cy0ei" tabindex="0" dir="ltr"><code><span class="line"><span class="s_252irl">let</span><span class="s_2a1oer"> post</span><span class="s_2ekfrt"> =</span><span class="s_indoxt"> createResource</span><span class="s_13ahmt">({</span><span class="s_fjrnv8">...</span><span class="s_13ahmt">})</span></span>
<span class="line"></span>
<span class="line"><span class="s_22m8k2">post</span><span class="s_1jjt6x">.</span><span class="s_11933w">data</span><span class="s_1th9sy"> // data returned from request</span></span>
<span class="line"><span class="s_22m8k2">post</span><span class="s_1jjt6x">.</span><span class="s_11933w">loading</span><span class="s_1th9sy"> // true when data is being fetched</span></span>
<span class="line"><span class="s_22m8k2">post</span><span class="s_1jjt6x">.</span><span class="s_11933w">error</span><span class="s_1th9sy"> // error that occurred from making the request or from validate function</span></span>
<span class="line"><span class="s_22m8k2">post</span><span class="s_1jjt6x">.</span><span class="s_11933w">promise</span><span class="s_1th9sy"> // promise object of the request, can be awaited</span></span>
<span class="line"><span class="s_22m8k2">post</span><span class="s_1jjt6x">.</span><span class="s_11933w">params</span><span class="s_1th9sy"> // params that were sent for making the request, if using makeParams, the return value is set here</span></span>
<span class="line"><span class="s_22m8k2">post</span><span class="s_1jjt6x">.</span><span class="s_11933w">fetched</span><span class="s_1th9sy"> // true when data has been fetched once, stays true after that</span></span>
<span class="line"><span class="s_22m8k2">post</span><span class="s_1jjt6x">.</span><span class="s_11933w">previousData</span><span class="s_1th9sy"> // when you call .reload(), previousData is set to current data, and then data is set to new returned data</span></span>
<span class="line"></span>
<span class="line"><span class="s_22m8k2">post</span><span class="s_1jjt6x">.</span><span class="s_indoxt">fetch</span><span class="s_13ahmt">()</span><span class="s_1th9sy"> // make the web request (fetch call)</span></span>
<span class="line"><span class="s_22m8k2">post</span><span class="s_1jjt6x">.</span><span class="s_indoxt">reload</span><span class="s_13ahmt">()</span><span class="s_1th9sy"> // alias to fetch</span></span>
<span class="line"><span class="s_22m8k2">post</span><span class="s_1jjt6x">.</span><span class="s_indoxt">submit</span><span class="s_13ahmt">()</span><span class="s_1th9sy"> // alias to fetch</span></span>
<span class="line"></span>
<span class="line"><span class="s_1th9sy">// you can also pass parameters while calling submit</span></span>
<span class="line"><span class="s_22m8k2">post</span><span class="s_1jjt6x">.</span><span class="s_indoxt">submit</span><span class="s_13ahmt">({</span><span class="s_r4oegk"> id</span><span class="s_1jjt6x">:</span><span class="s_40mev6"> 2</span><span class="s_13ahmt"> })</span></span>
<span class="line"></span>
<span class="line"><span class="s_1th9sy">// reset the state of this resource as a newly created one</span></span>
<span class="line"><span class="s_22m8k2">post</span><span class="s_1jjt6x">.</span><span class="s_indoxt">reset</span><span class="s_13ahmt">()</span></span>
<span class="line"></span>
<span class="line"><span class="s_1th9sy">// update url and params</span></span>
<span class="line"><span class="s_22m8k2">post</span><span class="s_1jjt6x">.</span><span class="s_indoxt">update</span><span class="s_13ahmt">({</span></span>
<span class="line"><span class="s_r4oegk">  url</span><span class="s_1jjt6x">:</span><span class="s_w1p9wo"> &#39;</span><span class="s_2575z4">/api/users</span><span class="s_w1p9wo">&#39;</span><span class="s_1jjt6x">,</span></span>
<span class="line"><span class="s_r4oegk">  params</span><span class="s_1jjt6x">:</span><span class="s_13ahmt"> {</span></span>
<span class="line"><span class="s_r4oegk">    id</span><span class="s_1jjt6x">:</span><span class="s_40mev6"> 2</span></span>
<span class="line"><span class="s_13ahmt">  }</span></span>
<span class="line"><span class="s_13ahmt">})</span></span>
<span class="line"></span>
<span class="line"><span class="s_1th9sy">// override data manually</span></span>
<span class="line"><span class="s_22m8k2">post</span><span class="s_1jjt6x">.</span><span class="s_indoxt">setData</span><span class="s_13ahmt">({</span></span>
<span class="line"><span class="s_r4oegk">  id</span><span class="s_1jjt6x">:</span><span class="s_40mev6"> 1</span><span class="s_1jjt6x">,</span></span>
<span class="line"><span class="s_r4oegk">  title</span><span class="s_1jjt6x">:</span><span class="s_w1p9wo"> &#39;</span><span class="s_2575z4">test</span><span class="s_w1p9wo">&#39;</span></span>
<span class="line"><span class="s_13ahmt">})</span></span>
<span class="line"><span class="s_1th9sy">// modify existing data</span></span>
<span class="line"><span class="s_22m8k2">post</span><span class="s_1jjt6x">.</span><span class="s_indoxt">setData</span><span class="s_13ahmt">(</span><span class="s_fsg3al">data</span><span class="s_50ecpt"> =&gt;</span><span class="s_13ahmt"> {</span></span>
<span class="line"><span class="s_29n2kq">  return</span><span class="s_22m8k2"> data</span><span class="s_1jjt6x">.</span><span class="s_indoxt">filter</span><span class="s_13ahmt">(</span><span class="s_fsg3al">d</span><span class="s_50ecpt"> =&gt;</span><span class="s_22m8k2"> d</span><span class="s_1jjt6x">.</span><span class="s_11933w">open</span><span class="s_13ahmt">)</span></span>
<span class="line"><span class="s_13ahmt">})</span></span></code></pre></div><h2 id="frappe-resource" tabindex="-1">Frappe Resource <a class="header-anchor" href="#frappe-resource" aria-label="Permalink to “Frappe Resource”">​</a></h2><p>Fetching data from a Frappe backend is no different from any other REST API service.</p><div class="language-vue"><button title="Copy Code" class="copy"></button><span class="lang">vue</span><pre class="shiki shiki-themes tokyo-night github-light s_2cy0ei" tabindex="0" dir="ltr"><code><span class="line"><span class="s_1zd9e2">&lt;</span><span class="s_1uuh8p">template</span><span class="s_1zd9e2">&gt;</span></span>
<span class="line"><span class="s_1zd9e2">  &lt;</span><span class="s_1uuh8p">Button</span><span class="s_1i4ay4"> @click</span><span class="s_1jjt6x">=</span><span class="s_w1p9wo">&quot;</span><span class="s_2575z4">todos.reload()</span><span class="s_w1p9wo">&quot;</span><span class="s_1i4ay4"> :loading</span><span class="s_1jjt6x">=</span><span class="s_w1p9wo">&quot;</span><span class="s_2575z4">todos.loading</span><span class="s_w1p9wo">&quot;</span><span class="s_1zd9e2">&gt;</span><span class="s_6am9cx"> Reload </span><span class="s_1zd9e2">&lt;/</span><span class="s_1uuh8p">Button</span><span class="s_1zd9e2">&gt;</span></span>
<span class="line"><span class="s_1zd9e2">  &lt;</span><span class="s_1uuh8p">pre</span><span class="s_1zd9e2">&gt;</span><span class="s_6am9cx">{{ todos }}</span><span class="s_1zd9e2">&lt;/</span><span class="s_1uuh8p">pre</span><span class="s_1zd9e2">&gt;</span></span>
<span class="line"><span class="s_1zd9e2">&lt;/</span><span class="s_1uuh8p">template</span><span class="s_1zd9e2">&gt;</span></span>
<span class="line"></span>
<span class="line"><span class="s_1zd9e2">&lt;</span><span class="s_1uuh8p">script</span><span class="s_1i4ay4"> setup</span><span class="s_1zd9e2">&gt;</span></span>
<span class="line"><span class="s_edvzsf">import</span><span class="s_13ahmt"> { </span><span class="s_4q1z3w">createResource</span><span class="s_13ahmt"> }</span><span class="s_edvzsf"> from</span><span class="s_w1p9wo"> &#39;</span><span class="s_2575z4">frappe-ui</span><span class="s_w1p9wo">&#39;</span></span>
<span class="line"><span class="s_252irl">let</span><span class="s_2a1oer"> todos</span><span class="s_2ekfrt"> =</span><span class="s_indoxt"> createResource</span><span class="s_13ahmt">({</span></span>
<span class="line"><span class="s_r4oegk">  url</span><span class="s_1jjt6x">:</span><span class="s_w1p9wo"> &#39;</span><span class="s_2575z4">/api/method/frappe.client.get_list</span><span class="s_w1p9wo">&#39;</span><span class="s_1jjt6x">,</span></span>
<span class="line"><span class="s_r4oegk">  params</span><span class="s_1jjt6x">:</span><span class="s_13ahmt"> {</span></span>
<span class="line"><span class="s_r4oegk">    doctype</span><span class="s_1jjt6x">:</span><span class="s_w1p9wo"> &#39;</span><span class="s_2575z4">ToDo</span><span class="s_w1p9wo">&#39;</span><span class="s_1jjt6x">,</span></span>
<span class="line"><span class="s_r4oegk">    filters</span><span class="s_1jjt6x">:</span><span class="s_13ahmt"> {</span></span>
<span class="line"><span class="s_12xt1b">      allocated_to</span><span class="s_1jjt6x">:</span><span class="s_w1p9wo"> &#39;</span><span class="s_2575z4">faris@frappe.io</span><span class="s_w1p9wo">&#39;</span><span class="s_1jjt6x">,</span></span>
<span class="line"><span class="s_13ahmt">    }</span><span class="s_1jjt6x">,</span></span>
<span class="line"><span class="s_13ahmt">  }</span><span class="s_1jjt6x">,</span></span>
<span class="line"><span class="s_13ahmt">})</span></span>
<span class="line"><span class="s_22m8k2">todos</span><span class="s_1jjt6x">.</span><span class="s_indoxt">fetch</span><span class="s_13ahmt">()</span></span>
<span class="line"><span class="s_1zd9e2">&lt;/</span><span class="s_1uuh8p">script</span><span class="s_1zd9e2">&gt;</span></span></code></pre></div><p>But the response format by Frappe Framework requires some parsing to be done to extract data and errors. Since <code>frappe-ui</code> is built primarily for Frappe backend apps, we can make it understand Frappe responses.</p><p>By default, resources use the <code>request</code> function exported from <code>frappe-ui</code> which is a generic Fetch API wrapper. There is another function <code>frappeRequest</code> which is a wrapper for Frappe REST API calls. To make resources use it, you have to do the following:</p><p><strong>main.js</strong></p><div class="language-js"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki shiki-themes tokyo-night github-light s_2cy0ei" tabindex="0" dir="ltr"><code><span class="line"><span class="s_edvzsf">import</span><span class="s_13ahmt"> { </span><span class="s_4q1z3w">setConfig</span><span class="s_1jjt6x">,</span><span class="s_4q1z3w"> frappeRequest</span><span class="s_13ahmt"> }</span><span class="s_edvzsf"> from</span><span class="s_w1p9wo"> &#39;</span><span class="s_2575z4">frappe-ui</span><span class="s_w1p9wo">&#39;</span></span>
<span class="line"><span class="s_indoxt">setConfig</span><span class="s_13ahmt">(</span><span class="s_w1p9wo">&#39;</span><span class="s_2575z4">resourceFetcher</span><span class="s_w1p9wo">&#39;</span><span class="s_1jjt6x">,</span><span class="s_22m8k2"> frappeRequest</span><span class="s_13ahmt">)</span></span></code></pre></div><p>Now, resources will use <code>frappeRequest</code> for making the web requests. You can also drop the <code>/api/method</code> part. The returned response will now set the data from <code>message</code> key and error from <code>exc</code>.</p><div class="language-vue"><button title="Copy Code" class="copy"></button><span class="lang">vue</span><pre class="shiki shiki-themes tokyo-night github-light s_2cy0ei" tabindex="0" dir="ltr"><code><span class="line"><span class="s_1zd9e2">&lt;</span><span class="s_1uuh8p">template</span><span class="s_1zd9e2">&gt;</span></span>
<span class="line"><span class="s_1zd9e2">  &lt;</span><span class="s_1uuh8p">Button</span><span class="s_1i4ay4"> @click</span><span class="s_1jjt6x">=</span><span class="s_w1p9wo">&quot;</span><span class="s_2575z4">todos.reload()</span><span class="s_w1p9wo">&quot;</span><span class="s_1i4ay4"> :loading</span><span class="s_1jjt6x">=</span><span class="s_w1p9wo">&quot;</span><span class="s_2575z4">todos.loading</span><span class="s_w1p9wo">&quot;</span><span class="s_1zd9e2">&gt;</span><span class="s_6am9cx"> Reload </span><span class="s_1zd9e2">&lt;/</span><span class="s_1uuh8p">Button</span><span class="s_1zd9e2">&gt;</span></span>
<span class="line"><span class="s_1zd9e2">  &lt;</span><span class="s_1uuh8p">pre</span><span class="s_1zd9e2">&gt;</span><span class="s_6am9cx">{{ post }}</span><span class="s_1zd9e2">&lt;/</span><span class="s_1uuh8p">pre</span><span class="s_1zd9e2">&gt;</span></span>
<span class="line"><span class="s_1zd9e2">&lt;/</span><span class="s_1uuh8p">template</span><span class="s_1zd9e2">&gt;</span></span>
<span class="line"></span>
<span class="line"><span class="s_1zd9e2">&lt;</span><span class="s_1uuh8p">script</span><span class="s_1i4ay4"> setup</span><span class="s_1zd9e2">&gt;</span></span>
<span class="line"><span class="s_edvzsf">import</span><span class="s_13ahmt"> { </span><span class="s_4q1z3w">createResource</span><span class="s_13ahmt"> }</span><span class="s_edvzsf"> from</span><span class="s_w1p9wo"> &#39;</span><span class="s_2575z4">frappe-ui</span><span class="s_w1p9wo">&#39;</span></span>
<span class="line"><span class="s_252irl">let</span><span class="s_2a1oer"> todos</span><span class="s_2ekfrt"> =</span><span class="s_indoxt"> createResource</span><span class="s_13ahmt">({</span></span>
<span class="line"><span class="s_6am9cx">- </span><span class="s_r4oegk">url</span><span class="s_1jjt6x">:</span><span class="s_w1p9wo"> &#39;</span><span class="s_2575z4">/api/method/frappe.client.get_list</span><span class="s_w1p9wo">&#39;</span><span class="s_1jjt6x">,</span></span>
<span class="line"><span class="s_6am9cx">+ </span><span class="s_r4oegk">url</span><span class="s_1jjt6x">:</span><span class="s_w1p9wo"> &#39;</span><span class="s_2575z4">frappe.client.get_list</span><span class="s_w1p9wo">&#39;</span><span class="s_1jjt6x">,</span></span>
<span class="line"><span class="s_r4oegk">  params</span><span class="s_1jjt6x">:</span><span class="s_13ahmt"> {</span></span>
<span class="line"><span class="s_r4oegk">    doctype</span><span class="s_1jjt6x">:</span><span class="s_w1p9wo"> &#39;</span><span class="s_2575z4">ToDo</span><span class="s_w1p9wo">&#39;</span><span class="s_1jjt6x">,</span></span>
<span class="line"><span class="s_r4oegk">    filters</span><span class="s_1jjt6x">:</span><span class="s_13ahmt"> {</span></span>
<span class="line"><span class="s_12xt1b">      allocated_to</span><span class="s_1jjt6x">:</span><span class="s_w1p9wo"> &#39;</span><span class="s_2575z4">faris@frappe.io</span><span class="s_w1p9wo">&#39;</span><span class="s_1jjt6x">,</span></span>
<span class="line"><span class="s_13ahmt">    }</span><span class="s_1jjt6x">,</span></span>
<span class="line"><span class="s_13ahmt">  }</span><span class="s_1jjt6x">,</span></span>
<span class="line"><span class="s_13ahmt">})</span></span>
<span class="line"><span class="s_22m8k2">todos</span><span class="s_1jjt6x">.</span><span class="s_indoxt">fetch</span><span class="s_13ahmt">()</span></span>
<span class="line"><span class="s_1zd9e2">&lt;/</span><span class="s_1uuh8p">script</span><span class="s_1zd9e2">&gt;</span></span></code></pre></div>`,34)])])}const u=a(c,[["render",e]]);export{h as __pageData,u as default};
